import React, { useState } from "react";
import { Link } from "react-router-dom";

const Home = () => {
  const [searchName, setSearchName] = useState("");
  const [searchLocation, setSearchLocation] = useState("");

  const events = [
    { 
      id: 1, 
      name: "Music Concert", 
      location: "Chennai", 
      date: "May 20, 2026",
      image: "https://images.unsplash.com/photo-1501386761578-eac5c94b800a?w=400&h=250&fit=crop"
    },
    { 
      id: 2, 
      name: "Dance Show", 
      location: "Bangalore", 
      date: "June 5, 2026",
      image: "https://images.unsplash.com/photo-1551836022-d5d88e9218df?w=400&h=250&fit=crop"
    },
    { 
      id: 3, 
      name: "Game Party", 
      location: "Hyderabad", 
      date: "July 10, 2026",
      image: "https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=400&h=250&fit=crop"
    },
    { 
      id: 4, 
      name: "Art Exhibition", 
      location: "Mumbai", 
      date: "August 15, 2026",
      image: "https://images.unsplash.com/photo-1513364776144-60967b0f800f?w=400&h=250&fit=crop"
    }
  ];

  const filteredEvents = events.filter(event =>
    event.name.toLowerCase().includes(searchName.toLowerCase()) &&
    event.location.toLowerCase().includes(searchLocation.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-50">

      {/* HERO SECTION */}
      <section className="bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 text-white py-16 text-center">
        <div className="max-w-6xl mx-auto px-4">
          <h1 className="text-4xl md:text-5xl font-bold mb-4">
            Welcome to EventHub 🎉
          </h1>
          <p className="text-lg mb-6">
            Discover and book amazing events in your city.
          </p>

          {/* SEARCH BOX */}
          <div className="bg-white/20 backdrop-blur-md rounded-xl p-4 max-w-3xl mx-auto">
            <div className="flex flex-col md:flex-row gap-3">
              <input
                type="text"
                placeholder="Search Event Name"
                value={searchName}
                onChange={(e) => setSearchName(e.target.value)}
                className="flex-1 px-4 py-2 rounded-lg text-gray-800 text-sm"
              />
              <input
                type="text"
                placeholder="Search Location"
                value={searchLocation}
                onChange={(e) => setSearchLocation(e.target.value)}
                className="flex-1 px-4 py-2 rounded-lg text-gray-800 text-sm"
              />
            </div>
          </div>
        </div>
      </section>

      {/* EVENTS SECTION */}
      <section className="py-12 px-4">
        <div className="max-w-7xl mx-auto">
          <h2 className="text-3xl font-bold text-center mb-8">
            Available Events
          </h2>

          {filteredEvents.length === 0 ? (
            <div className="text-center py-10">
              <p className="text-xl text-gray-500">No events found</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              {filteredEvents.map(event => (
                <div 
                  key={event.id} 
                  className="bg-white rounded-xl shadow-md overflow-hidden 
                             hover:shadow-xl transform hover:-translate-y-1 
                             transition duration-300 flex flex-col h-full"
                >
                  {/* IMAGE */}
                  <div className="h-48 w-full">
                    <img
                      src={event.image}
                      alt={event.name}
                      className="w-full h-full object-cover"
                    />
                  </div>

                  {/* CONTENT */}
                  <div className="p-4 flex flex-col flex-grow">
                    <h3 className="text-lg font-bold mb-2">
                      {event.name}
                    </h3>

                    <p className="text-gray-600 text-sm mb-1">
                      📍 {event.location}
                    </p>

                    <p className="text-gray-500 text-sm mb-4">
                      📅 {event.date}
                    </p>

                    {/* NAVIGATION BUTTON */}
                    <Link
                      to={`/events/${event.id}`}
                      className="mt-auto w-full"
                    >
                      <button className="w-full bg-purple-600 text-white py-2 rounded-lg text-sm font-semibold hover:bg-purple-700 transition">
                        Book Now 🎟️
                      </button>
                    </Link>

                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* CALL TO ACTION */}
      <section className="bg-gradient-to-r from-purple-600 to-pink-600 py-12 text-center text-white">
        <div className="max-w-4xl mx-auto px-4">
          <h2 className="text-3xl font-bold mb-3">
            Ready to Start Your Journey?
          </h2>
          <p className="text-base mb-5">
            Join thousands of event-goers today!
          </p>
          <Link
            to="/register"
            className="inline-block bg-white text-purple-600 px-8 py-3 rounded-full font-bold hover:scale-105 transition duration-300"
          >
            Sign Up Free 🚀
          </Link>
        </div>
      </section>

    </div>
  );
};

export default Home;
